INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-10ced7e2-moex-00561', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '居住於新竹之甲因投資需求，向住於桃園之乙借款新臺幣 300 萬元，雙方並以書面約定若因該借貸 關係發生爭議，合意由臺灣桃園地方法院管轄。嗣後，甲因投資失利，逾期未償還向乙所借之款項， 乙乃向臺灣新竹地方法院聲請依督促程序對甲發支付命令。下列敘述何者錯誤？', '["若甲接獲支付命令後，未於20日內提出異議，該支付命令即告確定，並得為執行名義", "若甲主張支付命令上所載債權不存在而提起確認之訴，法院依債務人聲請，得許甲提供相當並確 實之擔保，停止強制執行", "甲得於支付命令確定5日後，向地方法院以欠缺管轄權為由聲請再審", "若甲接獲支付命令後第15日，提出異議但未附理由，仍屬有效之異議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00562', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於民事訴訟審級之敘述，何者錯誤？', '["對於簡易程序之第一審裁判，得上訴或抗告於管轄之高等法院，其審判以合議行之", "對於小額程序之第一審裁判，得上訴或抗告於管轄之地方法院，其審判以合議行之", "上訴經撤回或因不合法而被駁回者，原則上附帶上訴失其效力", "上訴第三審法院，非以原判決違背法令為理由，不得為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00563', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於民事法院管轄之敘述，何者正確？', '["當事人得以合意定第一審及第二審管轄法院", "法院認為無管轄權者，原告與被告均得聲請以裁定移送於有管轄權之法院", "因侵權行為涉訟者，原告僅得於侵權行為地之法院起訴", "移送訴訟之聲請被駁回者，不得聲明不服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00564', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於民事訴訟法規定必要共同訴訟人之敘述，何者錯誤？', '["共同訴訟人中一人之行為有利益於共同訴訟人者，其效力及於全體", "共同訴訟人中一人之行為不利於共同訴訟人者，對於全體不生效力", "他造對於共同訴訟人中一人之行為，其效力及於全體", "共同訴訟人中之一人與他造合意停止者，其停止之效力及於全體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00565', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列何者係死亡宣告之法律效力？', '["被宣告死亡者，視為死亡", "被宣告死亡者之財產成為遺產", "被宣告死亡者喪失權利能力，縱然尚生存，亦無法為有效之法律行為", "被宣告死亡者若生還，得向法院聲請撤銷死亡宣告，回復一切能力與法律關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00566', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於代理之敘述，何者錯誤？', '["代理人所為或所受意思表示之效力，因其為限制行為能力人而受影響", "代理人經本人之許諾，或專履行債務者，得為自己代理", "代理權之限制及撤回，不得對抗無過失之善意第三人", "代理人依照本人所指示之意思而為代理時，其意思表示是否有被詐欺之事實，應就本人決之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00567', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於權利能力與行為能力之敘述，何者錯誤？', '["人之權利能力，始於出生，終於死亡", "受輔助宣告之人，無行為能力", "法人於法令限制內，有享受權利負擔義務之能力。但專屬於自然人之權利義務，不在此限", "權利能力及行為能力，不得拋棄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00568', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '甲將市價新臺幣（下同）100萬元之古董錶寄放於乙家中。某日，古董錶蒐藏家丙得知此事，向乙表 示願意高價收購該錶。乙心動不已，決定藉此中飽私囊，便花錢將該錶送交專業保養後，並因該錶 狀況甚佳，最終以150萬元出售於丙。嗣後，甲得知此事。下列敘述何者正確？', '["乙出售甲所有之古董錶於丙，係基於為甲管理事務的意思，屬於無因管理，乙得向甲請求為其支 出之保養該錶的費用，不以甲所得之利益為限", "乙出售甲所有之古董錶於丙，屬不法管理，甲僅得依侵權行為請求損害賠償100萬元", "乙出售甲所有之古董錶於丙，雖意在中飽私囊，但甲仍得享有因管理所得之利益150萬元", "乙出售甲所有之古董錶於丙，乙取得之買賣價金屬於不當得利，甲得向乙請求返還150萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00569', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '甲有一A地，先與乙訂立A地買賣契約，但尚未交付A地於乙且尚未辦理所有權移轉登記。嗣後， 甲與丙訂定買賣契約，將A地賣給丙，丙明知甲與乙訂約在先。下列敘述何者正確？', '["甲與丙訂立之買賣契約無效", "甲與乙訂立之買賣契約無效", "甲與乙丙之買賣契約均有效", "甲與乙及丙之買賣契約均效力未定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00570', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '依法律規定、習慣或法律行為，成一公同關係之數人，基於其公同關係，而共有一物者，為公同共 有人。下列關於公同共有之敘述，何者正確？', '["公同共有人得隨時請求分割公同共有物", "公同共有人得自由處分其應有部分", "公同共有人得自由使用收益公同共有物", "公同共有人得向無權占有人請求返還公同共有物於全體公同共有人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
